function toggleMenu(v){const d=document.querySelector('.ux-drawer25');if(!d)return;const open=v===undefined?!d.classList.contains('open'):v;d.classList.toggle('open',open);document.querySelector('.ux-drawer-scrim25')?.classList.toggle('open',open)}
