function hero(){const w=tr(),h=heroHost(route);if(!h)return;let x=h.querySelector(':scope > .ux-hero25');if(!x){x=document.createElement('section');x.className='ux-hero25';h.prepend(x)}const c=w.hero[route],key=`${lang()}-${route}`;if(x.dataset.renderKey===key)return;x.dataset.renderKey=key;x.innerHTML=`<div class="ux-hero-grid25" aria-hidden="true"></div><div class="ux-hero-orbit25" aria-hidden="true"><i>${route==='home'?'*':route==='learn'?'4':route==='prompt'?'AI':route==='workshop'?'M':'OK'}</i><span></span><span></span><span></span></div><div class="ux-hero-copy25"><small>${w.nav[routeOrder.indexOf(route)]}</small><h1>${esc(c[0])}</h1><p>${esc(c[1])}</p><button type="button" data-hero-action>${esc(c[2])} <b>&rarr;</b></button></div>${route==='learn'?`<ol class="ux-four25">${w.steps.map((s,i)=>`<li><em>${i+1}</em><span>${esc(s)}</span></li>`).join('')}</ol>`:''}`;x.querySelector('[data-hero-action]').onclick=()=>{if(route==='home')nativeGo('learn');else if(route==='learn')document.querySelector('.lesson-card')?.scrollIntoView({behavior:'smooth'});else if(route==='prompt')document.querySelector('.task-grid')?.scrollIntoView({behavior:'smooth'});else if(route==='workshop')document.querySelector('.training-hub .training-grid,.training-hub article')?.scrollIntoView({behavior:'smooth'});else document.querySelector('.ux-practice-grid25')?.scrollIntoView({behavior:'smooth'})}}
function bottom(){const w=tr(),h=heroHost(route);if(!h)return;let n=h.querySelector(':scope > .ux-chapter25');if(!n){n=document.createElement('section');n.className='ux-chapter25';h.append(n)}const i=routeOrder.indexOf(route),prev=routeOrder[Math.max(0,i-1)],next=routeOrder[Math.min(routeOrder.length-1,i+1)];n.innerHTML=`<div><small>${w.next}</small><h2>${esc(w.nav[Math.min(i+1,4)])}</h2></div><nav><button data-go="${prev}">&larr; ${esc(w.previous)}</button><button data-go="home">&#8962; ${esc(w.home)}</button><button data-top>&uarr; ${esc(w.top)}</button>${i<4?`<button class="primary" data-go="${next}">${esc(w.next)} &rarr;</button>`:''}</nav>`;n.querySelectorAll('[data-go]').forEach(b=>b.onclick=()=>nativeGo(b.dataset.go));n.querySelector('[data-top]').onclick=()=>scrollTo({top:0,behavior:'smooth'});if(n!==h.lastElementChild)h.append(n)}
function profile(){const w=tr(),builder=document.querySelector('.builder-section'),panel=document.querySelector('.prompt-panel');if(!builder||!panel)return;let s=builder.querySelector('.ux-profile25');if(!s){s=document.createElement('section');s.className='ux-profile25';builder.prepend(s)}let saved={};try{saved=JSON.parse(sessionStorage.getItem('uxProfile25')||'{}')}catch{}const di=Math.max(0,Number(saved.dept)||0),gi=Math.max(0,Number(saved.grade)||0),roleText=saved.role||w.roles[di];s.innerHTML=`<header><div><small>01 &middot; ${esc(w.profile)}</small><h2>${esc(w.profile)}</h2><p>${esc(w.profileHint)}</p></div><span>*</span></header><div class="ux-profile-fields25"><label>${esc(w.department)}<select data-profile="dept">${w.dept.map((x,i)=>`<option value="${i}" ${i===di?'selected':''}>${esc(x)}</option>`).join('')}</select></label><label>${esc(w.grade)}<select data-profile="grade">${w.grades.map((x,i)=>`<option value="${i}" ${i===gi?'selected':''}>${esc(x)}</option>`).join('')}</select></label><label>${esc(w.aiRole)}<input data-profile="role" value="${esc(roleText)}"></label></div>`;s.onchange=e=>{if(!e.target.matches('[data-profile]'))return;const d=Number(s.querySelector('[data-profile="dept"]').value),g=Number(s.querySelector('[data-profile="grade"]').value),role=s.querySelector('[data-profile="role"]');if(e.target.dataset.profile==='dept')role.value=w.roles[d];sessionStorage.setItem('uxProfile25',JSON.stringify({dept:d,grade:g,role:role.value}));updatePreview()};s.querySelector('[data-profile="role"]').oninput=()=>{sessionStorage.setItem('uxProfile25',JSON.stringify({dept:Number(s.querySelector('[data-profile="dept"]').value),grade:Number(s.querySelector('[data-profile="grade"]').value),role:s.querySelector('[data-profile="role"]').value}));updatePreview()};updatePreview()}
function profilePrompt(){const w=tr(),s=document.querySelector('.ux-profile25');if(!s)return'';const d=Number(s.querySelector('[data-profile="dept"]')?.value||0),g=Number(s.querySelector('[data-profile="grade"]')?.value||0),r=s.querySelector('[data-profile="role"]')?.value||w.roles[d];const lines={English:`[PROFESSIONAL PROFILE]\nUser department: ${w.dept[d]}\nUser position: ${w.grades[g]}\nYou are a ${r}.`,"\u{7E41}\u{9AD4}\u{4E2D}\u{6587}":`[\u{5C08}\u{696D}\u{8A2D}\u{5B9A}]\n\u{4F7F}\u{7528}\u{8005}\u{90E8}\u{9580}\u{FF1A}${w.dept[d]}\n\u{4F7F}\u{7528}\u{8005}\u{8077}\u{4F4D}\u{FF1A}${w.grades[g]}\n\u{4F60}\u{662F}\u{4E00}\u{4F4D}${r}\u{3002}`,"\u{7B80}\u{4F53}\u{4E2D}\u{6587}":`[\u{4E13}\u{4E1A}\u{8BBE}\u{7F6E}]\n\u{7528}\u{6237}\u{90E8}\u{95E8}\u{FF1A}${w.dept[d]}\n\u{7528}\u{6237}\u{804C}\u{4F4D}\u{FF1A}${w.grades[g]}\n\u{4F60}\u{662F}\u{4E00}\u{4F4D}${r}\u{3002}`,"\u{65E5}\u{672C}\u{8A9E}":`[\u{5C02}\u{9580}\u{8A2D}\u{5B9A}]\n\u{5229}\u{7528}\u{8005}\u{306E}\u{90E8}\u{9580}\u{FF1A}${w.dept[d]}\n\u{5229}\u{7528}\u{8005}\u{306E}\u{5F79}\u{8077}\u{FF1A}${w.grades[g]}\n\u{3042}\u{306A}\u{305F}\u{306F}${r}\u{3067}\u{3059}\u{3002}`,"\u{D55C}\u{AD6D}\u{C5B4}":`[\u{C804}\u{BB38} \u{C124}\u{C815}]\n\u{C0AC}\u{C6A9}\u{C790} \u{BD80}\u{C11C}: ${w.dept[d]}\n\u{C0AC}\u{C6A9}\u{C790} \u{C9C1}\u{C704}: ${w.grades[g]}\n\u{B2F9}\u{C2E0}\u{C740} ${r}\u{C785}\u{B2C8}\u{B2E4}.`};return lines[lang()]||lines.English}
function updatePreview(){const panel=document.querySelector('.prompt-panel'),pre=panel?.querySelector('pre');if(!panel||!pre)return;let p=panel.querySelector('.ux-role-preview25');if(!p){p=document.createElement('pre');p.className='ux-role-preview25';pre.before(p)}p.textContent=profilePrompt();const b=panel.querySelector('.copy-button');if(b){b.innerHTML=`<span>${esc(tr().copy)}</span><b>&rarr;</b>`}}
function practice(){const w=tr(),host=document.querySelector('.practice-lab');if(!host)return;let s=host.querySelector('.ux-practice-select25');if(!s){s=document.createElement('section');s.className='ux-practice-select25';const hero=host.querySelector('.ux-hero25');hero?.after(s)}s.innerHTML=`<header><small>PRACTICE CENTRE</small><h2>${esc(w.practiceTitle)}</h2><p>${esc(w.practiceHint)}</p></header><div class="ux-practice-grid25">${w.missions.map((m,i)=>`<button type="button" data-mission="${i}"><i>${m[3]}</i><strong>${esc(m[0])}</strong><span>${esc(w.duration)} &middot; ${esc(m[1])}</span><span>${esc(w.files)} &middot; ${esc(m[2])}</span><b>${esc(w.start)} &rarr;</b></button>`).join('')}</div>`;s.querySelectorAll('[data-mission]').forEach(b=>b.onclick=()=>{const i=Number(b.dataset.mission);document.querySelectorAll('.exercise-card').forEach((c,j)=>{c.classList.toggle('ux-open',j===i);c.hidden=j!==i});document.querySelector('.practice-lab .exercise-card:not([hidden])')?.scrollIntoView({behavior:'smooth',block:'start'})})}
